//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packagecommonimport("testing")funcTestArgsEmptyString(t*testing.T){t.Parallel()input:=``args:=ParseArgs(input)ifgot,want:=len(args.Positional),0;got!=want{t.Errorf("lengthofPositional=%v,want%v",got,want)}ifgot,want:=len(args.Keyword),0;got!=want{t.Errorf("lengthofKeyword=%v,want%v",got,want)}}funcTestArgsSinglePositional(t*testing.T){t.Parallel()input:=`aws_instance`args:=ParseArgs(input)ifgot,want:=len(args.Positional),1;got!=want{t.Errorf("lengthofPositional=%v,want%v",got,want)}ifgot,want:=args.Positional[0],"aws_instance";got!=want{t.Errorf("Positional[0]=%v,want%v",got,want)}ifgot,want:=len(args.Keyword),0;got!=want{t.Errorf("lengthofKeyword=%v,want%v",got,want)}}funcTestArgsSingleQuotedPositional(t*testing.T){t.Parallel()input:=`"aws_instance"`args:=ParseArgs(input)ifgot,want:=len(args.Positional),1;got!=want{t.Errorf("lengthofPositional=%v,want%v",got,want)}ifgot,want:=args.Positional[0],"aws_instance";got!=want{t.Errorf("Positional[0]=%v,want%v",got,want)}ifgot,want:=len(args.Keyword),0;got!=want{t.Errorf("lengthofKeyword=%v,want%v",got,want)}}funcTestArgsSingleKeyword(t*testing.T){t.Parallel()input:=`vv=42`args:=ParseArgs(input)ifgot,want:=len(args.Positional),0;got!=want{t.Errorf("lengthofPositional=%v,want%v",got,want)}ifgot,want:=len(args.Keyword),1;got!=want{t.Errorf("lengthofKeyword=%v,want%v",got,want)}ifgot,want:=args.Keyword["vv"],"42";got!=want{t.Errorf("Keyword[vv]=%v,want%v",got,want)}}funcTestArgsMultipleKeywords(t*testing.T){t.Parallel()input:=`vv=42,type=aws_instance`args:=ParseArgs(input)ifgot,want:=len(args.Positional),0;got!=want{t.Errorf("lengthofPositional=%v,want%v",got,want)}ifgot,want:=len(args.Keyword),2;got!=want{t.Errorf("lengthofKeyword=%v,want%v",got,want)}ifgot,want:=args.Keyword["vv"],"42";got!=want{t.Errorf("Keyword[vv]=%v,want%v",got,want)}ifgot,want:=args.Keyword["type"],"aws_instance";got!=want{t.Errorf("Keyword[type]=%v,want%v",got,want)}}funcTestArgsPostionalAndKeywords(t*testing.T){t.Parallel()input:=`first,vv=42,type=aws_instance,2`args:=ParseArgs(input)ifgot,want:=len(args.Positional),2;got!=want{t.Errorf("lengthofPositional=%v,want%v",got,want)}ifgot,want:=args.Positional[0],"first";got!=want{t.Errorf("Positional[0]=%v,want%v",got,want)}ifgot,want:=args.Positional[1],"2";got!=want{t.Errorf("Positional[1]=%v,want%v",got,want)}ifgot,want:=len(args.Keyword),2;got!=want{t.Errorf("lengthofKeyword=%v,want%v",got,want)}ifgot,want:=args.Keyword["vv"],"42";got!=want{t.Errorf("Keyword[vv]=%v,want%v",got,want)}ifgot,want:=args.Keyword["type"],"aws_instance";got!=want{t.Errorf("Keyword[type]=%v,want%v",got,want)}}